68	      mainItemsPremium += calculateItemPremium(item);
69	    }
70	  }
71	
72	  let total = mainItemsPremium;
73	  for (const [type, count] of componentCounts) {
74	    total += calculateComponentPremium(type, count);
75	  }
76	
77	  return total;
78	};
