80	export function processScenario(scenario: Scenario): ScenarioOutput {
81	  const results = scenario.steps.map((step) => {
82	    const basePremium = calculateBasePremium(step.items);
83	    const loyaltyDiscount = scenario.customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? basePremium * LOYALTY_DISCOUNT_RATE : 0;
84	    const policyPremium = basePremium + basePremium * FIRST_INSURANCE_SURCHARGE_RATE - loyaltyDiscount;
85	    const premium = Math.ceil(policyPremium) + PROCESSING_FEE;
86	    return { premium };
87	  });
88	  return { results };
89	}
